instance Proto.Extension.HasExtensions DataBlob where
  messageUnknownFields msg = msg.dataBlobUnknownFields
  setMessageUnknownFields !ufs msg = msg { dataBlobUnknownFields = ufs }

instance Semigroup DataBlob where
  a <> b = DataBlob
